mapper.update:
UPDATE t_account
SET last_change_at = #{lastChangeAt}
WHERE account_no = #{accountNo}

UPDATE t_account_balance
SET available_amount = #{availableAmount},
    frozen_amount = #{frozenAmount},
    in_transit_amount = #{inTransitAmount},
    updated_at = #{updatedAt}
WHERE account_no = #{accountNo}

UPDATE t_account_freeze
SET freeze_status = #{freezeStatus},
    freeze_reason = #{freezeReason},
    unfrozen_at = #{unfrozenAt}
WHERE freeze_no = #{freezeNo}

UPDATE t_account_adjustment
SET adjust_status = #{adjustStatus},
    approved_by = #{approvedBy},
    approved_at = #{approvedAt}
WHERE adjust_no = #{adjustNo}
